import json
import ast
from langflow.custom import Component
from langflow.io import MultilineInput, Output
from langflow.schema.message import Message

class ChatInput(Component):
    display_name = "Chat Input"
    description = "A stateless entry point that receives core prompts and bundles all other OpenAI parameters into a dictionary."
    icon = "MessagesSquare"
    name = "ChatInput"
    
    inputs = [
        MultilineInput(name="input_value",    display_name="User Prompt",    value="",   input_types=[]),
        MultilineInput(name="system_prompt",  display_name="System Prompt",  value="",   input_types=[]),
        MultilineInput(name="user_context",   display_name="User Context",   value="",   input_types=[]),
        MultilineInput(name="chat_history",   display_name="Chat History",   value="[]", input_types=[]),
        DictInput(name="model_configs",       display_name="Model Configs",  value={}, is_list=False, advanced=True),
        DictInput(name="params",              display_name="Params",         value={}, is_list=False, advanced=True),
    ]
    
    outputs = [
        Output(display_name="User Prompt",    name="user_message_out",   method="get_user_message",   types=["Message"], group_outputs=True),
        Output(display_name="User Context",   name="user_context_out",   method="get_user_context",   types=["Message"], group_outputs=True),
        Output(display_name="System Prompt",  name="system_prompt_out",  method="get_system_prompt",  types=["Message"], group_outputs=True),
        Output(display_name="Chat History",   name="chat_history_out",   method="get_chat_history",   types=["Message"], is_list=True, group_outputs=True),
        Output(display_name="Model Configs",  name="model_configs_out",  method="get_model_configs",  types=["dict"], group_outputs=True),
        Output(display_name="Params",         name="params_out",         method="get_params",         types=["dict"], group_outputs=True),
    ]

    def get_user_message(self) -> Message:
        return Message(text=self.input_value, sender="User", sender_name="User")
        
    def get_chat_history(self) -> list[Message]:
        messages = []
        if not self.chat_history:
            return messages
            
        try:
            history_list = json.loads(self.chat_history)
            for msg in history_list:
                role = msg.get("role", "User")
                sender_type = "AI" if role.lower() == "assistant" else "User"
                messages.append(Message(text=msg.get("content", ""), sender=sender_type, sender_name=role))
        except Exception as e:
            print(f"Error parsing chat history JSON: {e}")
            
        return messages
        
    def get_system_prompt(self) -> str:
        return Message(text=self.system_prompt, sender="AI", sender_name="Assistant")
        
    def get_user_context(self) -> str:
        return Message(text=self.user_context, sender="User", sender_name="User")

    def get_model_configs(self) -> dict:
        default_configs = {
            "general": {
                "provider": "GenAI.mil",
                "base_url": "",
                "model": "gemini-3.1-pro-preview",
            },
            "fast": {
                "provider": "GenAI.mil",
                "base_url": "",
                "model": "gemini-3-flash-preview",
            }
        }
        self.model_configs = {k:v for k,v in self.model_configs.items() if k.strip()}
        raw_input = self.model_configs if self.model_configs else {}
        if not raw_input or not isinstance(raw_input, dict):
            return default_configs
        return raw_input

    def get_params(self) -> dict:
        base_params = {
            "temperature": 1.0,
            "top_p":       1.0,
            "top_k":       None,
            "seed":        None,
            "max_tokens":  8192,
            "stream":      True,
        }
        raw_params = self.params if self.params else {}
        if isinstance(raw_params, dict):
            for k, v in raw_params.items():
                if not k.strip():
                    continue 
                if v is not None:
                    base_params[k] = v
        return base_params

