import re
from lfx.custom import Component # or langflow.custom based on your version
from lfx.io import MessageInput, Output
from lfx.schema import Message

class CatchInferenceErrorComponent(Component):
    display_name = "Catch Inference Error"
    description = "Catches specific API errors from an incoming message and routes them."
    icon = "lock"
    name = "CatchInferenceError"

    inputs = [
        MessageInput(
            name="response_message",
            display_name="Response Message",
            info="The message output from the inference node.",
            required=True
        ),
    ]

    outputs = [
        Output(display_name="Safe Result", name="safe_route", method="get_safe_result", group_outputs=True),
        Output(display_name="Error Result", name="error_route", method="get_error_message", group_outputs=True)
    ]

    def _handle_401_unlock_error(self, error_string: str) -> Message | None:
        if "401" in error_string and "API key locked" in error_string:
            url_match = re.search(r"'unlock_url':\s*'([^']+)'", error_string)
            if url_match:
                unlock_url = url_match.group(1)
                
                unlock_link = (
                    f'<a href="{unlock_url}" target="_blank" rel="noopener noreferrer">'
                    f'{unlock_url}</a>'
                )
                
                warning_text = (
                    "GenAI.mil API keys automatically lock every 8 hours as a security measure.\n\n"
                    "**Ctrl+Shift Click to open the following link** and unlock your API key.\n\n"
                    "Once unlocked, submit your query again.\n\n"
                    f"**{unlock_link}**"
                )
                return Message(text=warning_text)
        return None

    def _check_error_handlers(self, error_string: str) -> Message | None:
        handlers = [self._handle_401_unlock_error]
        for handler in handlers:
            formatted_error = handler(error_string)
            if formatted_error:
                return formatted_error
        return None

    def _parse_and_route(self, requesting_route: str):
        # 1. Safely extract text from the incoming Message
        if isinstance(self.response_message, Message):
            msg_text = self.response_message.text
        else:
            msg_text = self.response_message

        # 2. Check for errors ONLY if the text is a string
        # If it's a generator, it's a healthy live stream and we bypass the error check!
        if isinstance(msg_text, str):
            error_message_obj = self._check_error_handlers(msg_text)
            is_error = error_message_obj is not None
        else:
            is_error = False
            error_message_obj = None

        # 3. Routing Logic (Kill inactive branches)
        if is_error:
            self.stop("safe_route")
            if hasattr(self, "graph") and hasattr(self.graph, "exclude_branch_conditionally"):
                self.graph.exclude_branch_conditionally(self._id, output_name="safe_route")
        else:
            self.stop("error_route")
            if hasattr(self, "graph") and hasattr(self.graph, "exclude_branch_conditionally"):
                self.graph.exclude_branch_conditionally(self._id, output_name="error_route")

        # 4. Return Logic
        if requesting_route == "safe_route":
            if is_error:
                return Message(text="") # Dead branch
            return self.response_message # Live branch: Pass the original safe message (and its generator!)

        if requesting_route == "error_route":
            if not is_error:
                return Message(text="") # Dead branch
            return error_message_obj # Live branch: Pass the formatted warning

    def get_safe_result(self) -> Message:
        return self._parse_and_route("safe_route")

    def get_error_message(self) -> Message:
        return self._parse_and_route("error_route")
